import React from 'react';
import { PageHeader } from '@/components/dashboard/PageHeader';
import { Button } from '@/components/ui/button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';

import { CheckCircle2, AlertTriangle } from 'lucide-react';
import { toast } from 'sonner';
import { useData } from '@/lib/BookingContext';



export default function StaffWarnings() {
  const { warnings, payPenalty } = useData();

  const handlePayPenalty = (warningId: string, amount?: number) => {
    payPenalty(warningId);
    toast.success(`Penalty of ₹${amount ?? 0} marked as paid.`);
  };

  // Show all warnings from global context
  const allWarnings = warnings;

  return (
    <div className="space-y-6">
      <PageHeader
        title="Warnings & Penalties"
        description="Track student penalties and mark payments"
      />

      <div className="bg-card rounded-xl border border-border shadow-card overflow-x-auto">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Student</TableHead>
              <TableHead>Level</TableHead>
              <TableHead>Reason</TableHead>
              <TableHead>Amount</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Issued By</TableHead>
              <TableHead>Date</TableHead>
              <TableHead className="text-right">Action</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {allWarnings.length === 0 && (
              <TableRow>
                <TableCell colSpan={8} className="text-center text-muted-foreground py-10">
                  No penalties on record
                </TableCell>
              </TableRow>
            )}
            {allWarnings.map(w => (
              <TableRow key={w.id} className={w.isPaid ? 'opacity-50' : ''}>
                <TableCell className="font-medium">{w.studentName}</TableCell>
                <TableCell>
                  <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${
                    w.level === 3 ? 'bg-destructive/10 text-destructive'
                    : w.level === 2 ? 'bg-orange-500/10 text-orange-600'
                    : 'bg-yellow-500/10 text-yellow-600'
                  }`}>
                    Level {w.level}
                  </span>
                </TableCell>
                <TableCell className="text-muted-foreground">{w.reason}</TableCell>
                <TableCell>
                  {w.amount
                    ? <span className="font-bold text-destructive">₹{w.amount}</span>
                    : <span className="text-muted-foreground">—</span>
                  }
                </TableCell>
                <TableCell>
                  {w.isPaid ? (
                    <Badge className="bg-green-500/10 text-green-600 border-transparent">
                      <CheckCircle2 className="w-3 h-3 mr-1" /> Paid
                    </Badge>
                  ) : (
                    <Badge className="bg-destructive/10 text-destructive border-transparent">
                      <AlertTriangle className="w-3 h-3 mr-1" /> Unpaid
                    </Badge>
                  )}
                </TableCell>
                <TableCell className="text-muted-foreground">{w.issuedBy}</TableCell>
                <TableCell className="text-muted-foreground">
                  {new Date(w.issuedAt).toLocaleDateString()}
                </TableCell>
                <TableCell className="text-right">
                  {!w.isPaid ? (
                    <Button
                      size="sm"
                      variant="outline"
                      className="text-[10px] h-7 px-2 border-green-500/50 text-green-600 hover:bg-green-50"
                      onClick={() => handlePayPenalty(w.id, w.amount)}
                    >
                      Pay
                    </Button>
                  ) : (
                    <span className="text-xs text-muted-foreground">Paid</span>
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}
